import{_ as s,o as a,c as t,ai as i}from"./chunks/framework.DMjte4z8.js";const g=JSON.parse('{"title":"JASS 常用函数参考","description":"","frontmatter":{"title":"JASS 常用函数参考","category":"scripting","updated":"2026-05-08T00:00:00.000Z","model":"openai/MiniMax-M2.7-highspeed","quality_score":0.72,"discovered_via":"manual","sources":["https://jass.fandom.com/wiki/Functions","https://github.com/lep/jassdoc","https://jass.sourceforge.net/doc/","https://blog.csdn.net/weixin_32251525/article/details/143220228","https://www.hiveworkshop.com/threads/beginning-jass-tutorial-series.30765/","https://forum.wc3edit.net/viewtopic.php?t=11005","https://wc3we.fandom.com/wiki/Jass_Coding","https://www.thehelper.net/threads/is-there-a-complete-jass-function-list.54372/"]},"headers":[],"relativePath":"scripting/jass-常用函数参考.md","filePath":"scripting/jass-常用函数参考.md","lastUpdated":1778216780000}'),n={name:"scripting/jass-常用函数参考.md"};function o(r,e,l,d,c,p){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="jass-常用函数参考" tabindex="-1">JASS 常用函数参考 <a class="header-anchor" href="#jass-常用函数参考" aria-label="Permalink to “JASS 常用函数参考”">​</a></h1><h2 id="jass-简介与入门基础" tabindex="-1">JASS 简介与入门基础 <a class="header-anchor" href="#jass-简介与入门基础" aria-label="Permalink to “JASS 简介与入门基础”">​</a></h2><p>本节将带你认识 JASS 脚本语言，了解它是什么、为什么地图需要它，以及如何打开编辑器开始编写你的第一行代码。学完本节后，你将能够区分 JASS 和可视化触发器，并成功打开 JASS 脚本编辑器查看代码[^3]。</p><h3 id="什么是-jass-及其作用" tabindex="-1">什么是 JASS 及其作用 <a class="header-anchor" href="#什么是-jass-及其作用" aria-label="Permalink to “什么是 JASS 及其作用”">​</a></h3><p>JASS 是 Warcraft III（魔兽争霸3）内置的脚本编程语言，全称是 &quot;JavaScript-like Assistant Scripting System&quot;（类JavaScript辅助脚本系统）[^3]。简单来说，<strong>JASS 就是让地图&quot;动起来&quot;的命令清单</strong>。</p><p>当你想要实现以下功能时就需要用到 JASS：</p><ul><li>让单位在受到攻击时自动播放特效</li><li>创建复杂的技能系统（如连锁闪电）</li><li>编写AI让电脑控制的敌人更聪明</li><li>管理游戏中的计时器和事件</li></ul><blockquote><p><strong>💡 新手提示</strong>：你可以把 JASS 想象成一份&quot;任务清单&quot;，你告诉电脑&quot;当XX发生时，就去做YY事情&quot;。World Editor（世界编辑器）中的<strong>触发器编辑器</strong>本质上就是用可视化方式帮你写 JASS 代码[^5]。</p></blockquote><h3 id="jass-脚本编辑器开启方法" tabindex="-1">JASS 脚本编辑器开启方法 <a class="header-anchor" href="#jass-脚本编辑器开启方法" aria-label="Permalink to “JASS 脚本编辑器开启方法”">​</a></h3><p>虽然触发器编辑器可以可视化地创建逻辑，但你也可以直接查看和编写原始 JASS 代码。以下是打开方法：</p><ol><li><strong>启动 World Editor</strong> — 双击桌面图标或在魔兽争霸3文件夹中找到 <code>World Editor.exe</code> 打开[^3]</li><li><strong>打开或创建地图</strong> — 点击菜单栏 &quot;文件&quot; → &quot;新建&quot; 创建一个空白地图，或用 Ctrl+O 打开现有地图</li><li><strong>进入触发器编辑器</strong> — 在工具栏找到并点击 <strong>&quot;触发器编辑器&quot;</strong>（也叫&quot;触发编辑器&quot;），快捷键是 F4</li><li><strong>查看 JASS 代码</strong> — 在触发器列表中选中任意触发器，双击右侧的&quot;动作&quot;区域，你将看到对应的 JASS 代码窗口[^5]</li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常把触发器编辑器和 JASS 编辑器搞混。触发器编辑器是可视化界面，而 JASS 代码显示在代码窗口中。如果你想纯手写 JASS，需要在地图脚本中编写（右键点击&quot;地图脚本&quot;选择&quot;编辑&quot;）[^7]。</p></blockquote><h3 id="jass-基本语法结构" tabindex="-1">JASS 基本语法结构 <a class="header-anchor" href="#jass-基本语法结构" aria-label="Permalink to “JASS 基本语法结构”">​</a></h3><p>JASS 的代码由几个核心元素组成，理解它们是入门的关键[^4]：</p><p><strong>1. 函数（Function）</strong> 函数是 JASS 的基本执行单元，每段代码都写在函数内部：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>function MyFunction takes nothing returns nothing</span></span>
<span class="line"><span>    // 你的代码写在这里</span></span>
<span class="line"><span>endfunction</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li><code>takes nothing</code> 表示这个函数不需要任何参数</li><li><code>returns nothing</code> 表示函数执行完不返回任何值</li></ul><p><strong>2. 变量（Variable）</strong> 变量用于存储数据，就像一个带名字的盒子：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>local integer myScore = 0    // 整数变量</span></span>
<span class="line"><span>local unit hero               // 单位变量</span></span>
<span class="line"><span>local boolean isAlive = true  // 布尔变量（真假）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>3. 常用关键字</strong></p><ul><li><code>call</code> — 调用一个函数：<code>call DisplayTextToPlayer(...)</code></li><li><code>set</code> — 给变量赋值：<code>set myScore = 100</code></li><li><code>if/then/else</code> — 条件判断</li><li><code>loop/endloop</code> — 循环执行[^5]</li></ul><blockquote><p><strong>💡 新手提示</strong>：JASS 对大小写敏感！<code>Set</code> 和 <code>set</code> 是不同的。写代码时务必保持大小写一致，否则运行时会报错[^4]。</p></blockquote><h3 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h3><p>完成以上内容后，你应该已经：</p><ul><li>✅ 理解了 JASS 是用于控制地图逻辑的脚本语言</li><li>✅ 学会了如何在 World Editor 中打开触发器编辑器并查看 JASS 代码</li><li>✅ 认识了函数、变量、关键字等基本语法元素</li></ul><p>这些知识将为你后续学习更复杂的 JASS 编程打下坚实基础！</p><h2 id="常用输出与调试函数" tabindex="-1">常用输出与调试函数 <a class="header-anchor" href="#常用输出与调试函数" aria-label="Permalink to “常用输出与调试函数”">​</a></h2><p>本节将带你认识三个最常用的输出与调试函数：<code>BJDebugMsg</code>、<code>DisplayTextToPlayer</code> 和 <code>SendSysMessage</code>。学完本节后，你将能够在游戏中显示文字信息，随时检查变量值是否正确，再也不用担心写完触发器后不知道程序运行到哪一步了。</p><hr><h3 id="bjdebugmsg-调试消息输出" tabindex="-1">BJDebugMsg 调试消息输出 <a class="header-anchor" href="#bjdebugmsg-调试消息输出" aria-label="Permalink to “BJDebugMsg 调试消息输出”">​</a></h3><p><strong>BJDebugMsg</strong> 是暴雪封装好的BJ函数（可以直接理解为&quot;简化版函数&quot;），用于向所有玩家同时显示一行调试信息[^1]。</p><p><strong>语法格式：</strong></p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>call BJDebugMsg(消息内容)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>适用场景：</strong></p><ul><li>调试时想知道某段代码是否被执行</li><li>检查某个变量的当前值</li><li>追踪触发器的执行流程</li></ul><blockquote><p><strong>💡 新手提示</strong>：BJDebugMsg 显示的信息只有游戏主持人（单人模式）或所有玩家能看到，但<strong>不会保存在任何日志文件里</strong>，关闭游戏后这些消息就消失了。如果你想保存调试记录，建议同时使用其他方式记录。</p></blockquote><hr><h3 id="displaytexttoplayer-玩家信息显示" tabindex="-1">DisplayTextToPlayer 玩家信息显示 <a class="header-anchor" href="#displaytexttoplayer-玩家信息显示" aria-label="Permalink to “DisplayTextToPlayer 玩家信息显示”">​</a></h3><p><strong>DisplayTextToPlayer</strong> 是原生函数（Native Function），比 BJ 函数更底层、功能更精确[^2]。它可以将消息发送给<strong>指定的一位玩家</strong>，并显示在屏幕特定位置。</p><p><strong>语法格式：</strong></p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>call DisplayTextToPlayer(玩家变量, X坐标, Y坐标, 消息内容)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>参数说明：</strong></p><table tabindex="0"><thead><tr><th>参数</th><th>含义</th><th>示例值</th></tr></thead><tbody><tr><td>玩家变量</td><td>要接收消息的玩家编号（0-11）</td><td>Player(0)</td></tr><tr><td>X坐标</td><td>屏幕上横向位置（0.0-1.0）</td><td>0.5</td></tr><tr><td>Y坐标</td><td>屏幕上纵向位置（0.0-1.0）</td><td>0.5</td></tr><tr><td>消息内容</td><td>要显示的字符串</td><td>&quot;游戏开始！&quot;</td></tr></tbody></table><p><strong>适用场景：</strong></p><ul><li>只让某个特定玩家看到提示（如剧情对话）</li><li>为不同玩家显示不同信息</li><li>显示UI提示文本</li></ul><blockquote><p><strong>⚠️ 常见错误</strong>：新手容易把 X 和 Y 坐标写成整数（如 500、300），这会导致消息<strong>无法显示或显示位置异常</strong>。记住，坐标值范围是 <strong>0.0 到 1.0</strong>，0.5 代表屏幕正中央。</p></blockquote><hr><h3 id="sendsysmessage-系统消息函数" tabindex="-1">SendSysMessage 系统消息函数 <a class="header-anchor" href="#sendsysmessage-系统消息函数" aria-label="Permalink to “SendSysMessage 系统消息函数”">​</a></h3><p><strong>SendSysMessage</strong> 通常是自定义封装的消息函数，功能类似 <code>DisplayTextToPlayer</code>，但更简洁——只需指定玩家和消息内容，位置固定为屏幕左下方系统消息区域。</p><p><strong>语法格式（取决于地图作者的封装方式）：</strong></p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>call SendSysMessage(玩家变量, 消息内容)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>与 BJDebugMsg 的区别：</strong></p><table tabindex="0"><thead><tr><th>对比项</th><th>BJDebugMsg</th><th>SendSysMessage</th></tr></thead><tbody><tr><td>显示对象</td><td>所有玩家</td><td>指定玩家</td></tr><tr><td>显示位置</td><td>屏幕中央</td><td>系统消息区（左下）</td></tr><tr><td>是否原生</td><td>BJ封装函数</td><td>取决于地图实现</td></tr></tbody></table><blockquote><p><strong>💡 新手提示</strong>：如果地图没有预先定义 SendSysMessage，你可以直接使用 <code>DisplayTextToPlayer</code> 并把坐标设为左下角（如 X=0.01, Y=0.01）来实现类似效果。</p></blockquote><hr><h3 id="小结-1" tabindex="-1">小结 <a class="header-anchor" href="#小结-1" aria-label="Permalink to “小结”">​</a></h3><p>掌握这三个函数后，你现在可以：</p><ul><li>✅ 使用 <code>BJDebugMsg</code> 快速输出调试信息，验证代码是否运行</li><li>✅ 使用 <code>DisplayTextToPlayer</code> 精准控制哪位玩家、在哪里看到什么消息</li><li>✅ 使用或自定义 <code>SendSysMessage</code> 实现统一的系统提示风格</li></ul><p><strong>下一步建议</strong>：试着在一个简单触发器中加入 <code>BJDebugMsg(&quot;触发器已执行！&quot;)</code>，运行地图后观察消息是否出现。如果能正常显示，说明你已成功迈出 JASS 调试的第一步！</p><h2 id="单位创建与操作函数" tabindex="-1">单位创建与操作函数 <a class="header-anchor" href="#单位创建与操作函数" aria-label="Permalink to “单位创建与操作函数”">​</a></h2><p>本节将教你如何在JASS中<strong>创建游戏单位</strong>和<strong>控制单位移动</strong>，这是制作RPG地图最基础、也是最常用的技能。学完本节后，你就能让怪物出现、让NPC移动到指定位置了。</p><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>第一步：理解单位创建函数</strong> — 在JASS中，<code>CreateUnit</code> 是最基础的单位创建函数。它的基本语法是：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>CreateUnit(id, unitid, x, y, face)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li><code>id</code> 是玩家编号（0-11，对应红、绿、蓝等12个玩家）</li><li><code>unitid</code> 是单位类型ID（如 &quot;hpea&quot; 代表农民）</li><li><code>x</code> 和 <code>y</code> 是坐标位置</li><li><code>face</code> 是单位朝向角度（0-360度）[^1][^2]</li></ul></li><li><p><strong>第二步：使用 CreateUnitAtLoc 创建单位</strong> — 如果你想在<strong>区域（Location）</strong>而非精确坐标处创建单位，可以使用 <code>CreateUnitAtLoc</code>。这个函数在制作刷怪点时特别有用，因为它会自动把单位放置在区域中心[^2]：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>CreateUnitAtLoc(id, unitid, loc, face)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>第三步：移动单位到指定位置</strong> — 创建单位后，你需要移动它们。使用 <code>SetUnitPosition</code> 可以瞬间把单位传送到精确坐标[^2]：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>call SetUnitPosition(unitHandle, x, y)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或者分别设置X和Y坐标：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>call SetUnitX(unitHandle, x)</span></span>
<span class="line"><span>call SetUnitY(unitHandle, y)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></li><li><p><strong>第四步：修改单位属性</strong> — 创建单位后，你可以修改它的属性。常用函数包括：</p><ul><li><code>SetUnitState</code> — 修改生命值、魔法值等</li><li><code>SetUnitMoveSpeed</code> — 修改移动速度</li><li><code>SetUnitFacing</code> — 修改朝向角度[^2][^4]</li></ul></li></ol><blockquote><p><strong>💡 新手提示</strong>：创建单位时记得把返回值（单位句柄）存到变量里！否则你创建了单位却无法控制它，就像凭空消失了。</p></blockquote><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常把 <code>CreateUnit</code> 和 <code>CreateUnitAtLoc</code> 搞混。前者需要精确的X/Y坐标，后者只需要一个区域对象（用 <code>Location</code> 函数创建）。搞混会导致单位出现在奇怪的位置或报错。</p></blockquote><h3 id="小结-2" tabindex="-1">小结 <a class="header-anchor" href="#小结-2" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你应该掌握：</p><ul><li>如何使用 <code>CreateUnit</code> 和 <code>CreateUnitAtLoc</code> 在地图上生成单位</li><li>如何使用 <code>SetUnitPosition</code> 系列函数移动单位</li><li>如何用变量保存和操作单位句柄</li></ul><p>建议动手练习：尝试创建一个&quot;刷怪触发器&quot;，当玩家进入某个区域时，自动在附近生成一只怪物。</p><h2 id="触发器事件注册函数" tabindex="-1">触发器事件注册函数 <a class="header-anchor" href="#触发器事件注册函数" aria-label="Permalink to “触发器事件注册函数”">​</a></h2><p>本节将介绍三个在 JASS 中常用的触发器事件注册函数，它们分别是监听变量变化、设置定时器、以及手动执行触发器的事件[^2]。学完本节后，你将能够在地图中实现&quot;当某个变量改变时自动触发&quot;、&quot;每隔一段时间执行某段代码&quot;等常见功能。</p><h3 id="操作步骤-1" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤-1" aria-label="Permalink to “操作步骤”">​</a></h3><ol><li><p><strong>TriggerRegisterVariableEvent — 监听变量变化</strong><br> 这个函数用于&quot;注册&quot;一个事件，当指定变量的值发生变化时自动触发[^2]。语法为：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>TriggerRegisterVariableEvent(trig, varName, opcode, limitval)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>其中 <code>varName</code> 是变量名（字符串格式），<code>opcode</code>是比较方式（如 <code>LESS THAN</code>、<code>EQUAL</code> 等），<code>limitval</code>是比较的数值。例如监听整数变量 <code>udg_Score</code> 是否大于 100：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>call TriggerRegisterVariableEvent(gg_trg_CheckScore, &quot;udg_Score&quot;, GREATER THAN, 100)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>TriggerRegisterTimerEvent — 设置定时器事件</strong><br> 这个函数可以让触发器在固定时间间隔后自动执行[^2]。语法为：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>TriggerRegisterTimerEvent(trig, timeout, periodic)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>参数 <code>timeout</code> 是时间（秒），<code>periodic</code> 为 <code>true</code> 时表示重复执行，<code>false</code> 则只执行一次。例如让触发器每 5 秒执行一次：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>call TriggerRegisterTimerEvent(gg_trg_TimerLoop, 5.0, true)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>TriggerExecute — 手动执行触发器</strong><br> 这个函数可以让你在代码中主动&quot;调用&quot;另一个触发器立即执行[^2]。语法为：</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>TriggerExecute(trig)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>注意：TriggerExecute 会忽略触发器的条件（conditions），直接执行动作。</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：新手经常混淆 <code>TriggerRegisterTimerEvent</code> 和 <code>TriggerSleepAction</code>。前者是注册事件（在触发器编辑器中使用），后者是代码中延时（暂停当前函数执行）。在 JASS 代码中请使用 <code>TriggerSleepAction(1.0)</code> 来延时，而不是注册新的定时器事件。</p></blockquote><h3 id="小结-3" tabindex="-1">小结 <a class="header-anchor" href="#小结-3" aria-label="Permalink to “小结”">​</a></h3><p>完成以上步骤后，你已经掌握了三种触发器事件注册的方法：监听变量变化、设置定时器、以及手动执行触发器。建议先在地图中创建一个简单的计时触发器，验证功能正常后再进行更复杂的逻辑开发。</p><h2 id="数学运算与逻辑函数" tabindex="-1">数学运算与逻辑函数 <a class="header-anchor" href="#数学运算与逻辑函数" aria-label="Permalink to “数学运算与逻辑函数”">​</a></h2><p>本节将带你认识JASS中最常用的数学计算和逻辑判断工具。学完本节后，你就能在触发器中使用数学公式计算伤害值、判断单位距离等核心功能——这是制作技能系统和游戏逻辑的基础！</p><hr><h3 id="_1-数学运算函数" tabindex="-1">1. 数学运算函数 <a class="header-anchor" href="#_1-数学运算函数" aria-label="Permalink to “1. 数学运算函数”">​</a></h3><h4 id="第一步-了解数学函数的分类" tabindex="-1">第一步：了解数学函数的分类 <a class="header-anchor" href="#第一步-了解数学函数的分类" aria-label="Permalink to “第一步：了解数学函数的分类”">​</a></h4><p>JASS的数学函数主要分为<strong>原生函数</strong>（Native）和<strong>BJ辅助函数</strong>两类[^1]：</p><ul><li><strong>原生函数</strong>是JASS语言自带的底层函数，名称通常较短，如 <code>Sin(x)</code>、<code>Cos(x)</code></li><li><strong>BJ辅助函数</strong>是暴雪封装的&quot;友好版本&quot;，名称带有 <code>BJ</code> 后缀，如 <code>SinBJ(x)</code>、<code>CosBJ(x)</code>，会自动处理一些边界情况[^2]</li></ul><h4 id="第二步-认识常用数学函数" tabindex="-1">第二步：认识常用数学函数 <a class="header-anchor" href="#第二步-认识常用数学函数" aria-label="Permalink to “第二步：认识常用数学函数”">​</a></h4><p>以下是新手最常用的数学函数：</p><table tabindex="0"><thead><tr><th>函数</th><th>作用</th><th>示例</th></tr></thead><tbody><tr><td><code>Sin(x)</code> / <code>SinBJ(x)</code></td><td>计算正弦值</td><td><code>SetAngle = Sin(30 * bj_DEGTORAD)</code></td></tr><tr><td><code>Cos(x)</code> / <code>CosBJ(x)</code></td><td>计算余弦值</td><td><code>SetAngle = Cos(60 * bj_DEGTORAD)</code></td></tr><tr><td><code>SquareRoot(x)</code></td><td>计算平方根</td><td><code>SetDist = SquareRoot(dx*dx + dy*dy)</code></td></tr><tr><td><code>Pow(base, exp)</code></td><td>计算幂次方</td><td><code>SetValue = Pow(2, 8)</code></td></tr><tr><td><code>Deg2Rad</code> / <code>Rad2Deg</code></td><td>角度与弧度转换</td><td><code>SetRad = degrees * bj_DEGTORAD</code></td></tr></tbody></table><blockquote><p><strong>💡 新手提示</strong>：<code>bj_DEGTORAD</code> 是一个常数（约等于 0.01745），用于将角度转换为弧度。在JASS中，三角函数使用的是弧度制，不是角度制！这是新手最容易搞错的地方。</p></blockquote><h4 id="第三步-掌握整数与浮点数转换" tabindex="-1">第三步：掌握整数与浮点数转换 <a class="header-anchor" href="#第三步-掌握整数与浮点数转换" aria-label="Permalink to “第三步：掌握整数与浮点数转换”">​</a></h4><p>JASS区分<strong>整数</strong>（integer）和<strong>实数</strong>（real），需要经常相互转换[^4]：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>I2R(i)    // 将整数转换为实数</span></span>
<span class="line"><span>R2I(r)    // 将实数转换为整数（会取整）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><blockquote><p><strong>⚠️ 常见错误</strong>：直接用整数除以整数会丢失小数部分。例如 <code>5 / 2</code> 的结果是 <code>2</code>，而不是 <code>2.5</code>。正确做法是 <code>I2R(5) / I2R(2)</code> 或 <code>5.0 / 2.0</code>。</p></blockquote><hr><h3 id="_2-条件判断与比较函数" tabindex="-1">2. 条件判断与比较函数 <a class="header-anchor" href="#_2-条件判断与比较函数" aria-label="Permalink to “2. 条件判断与比较函数”">​</a></h3><h4 id="第一步-理解比较运算符" tabindex="-1">第一步：理解比较运算符 <a class="header-anchor" href="#第一步-理解比较运算符" aria-label="Permalink to “第一步：理解比较运算符”">​</a></h4><p>JASS中使用以下比较运算符[^3]：</p><table tabindex="0"><thead><tr><th>运算符</th><th>含义</th></tr></thead><tbody><tr><td><code>==</code></td><td>等于</td></tr><tr><td><code>!=</code></td><td>不等于</td></tr><tr><td><code>&lt;</code></td><td>小于</td></tr><tr><td><code>&gt;</code></td><td>大于</td></tr><tr><td><code>&lt;=</code></td><td>小于等于</td></tr><tr><td><code>&gt;=</code></td><td>大于等于</td></tr></tbody></table><h4 id="第二步-组合多个条件" tabindex="-1">第二步：组合多个条件 <a class="header-anchor" href="#第二步-组合多个条件" aria-label="Permalink to “第二步：组合多个条件”">​</a></h4><p>当需要同时满足多个条件时，使用逻辑函数[^3]：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>and(条件1, 条件2)  // 两个条件都满足才返回 true</span></span>
<span class="line"><span>or(条件1, 条件2)   // 任一条件满足就返回 true</span></span>
<span class="line"><span>not(条件)          // 取反，true变false，false变true</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>示例</strong>：判断单位是否在范围内且生命值大于50</p><div class="language-jass line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">jass</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>if and( DistanceBetweenUnits(u1, u2) &lt; 300, GetUnitLifePercent(u1) &gt; 50 ) then</span></span>
<span class="line"><span>    // 执行技能效果</span></span>
<span class="line"><span>endif</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><blockquote><p><strong>💡 新手提示</strong>：比较函数的返回值是<strong>布尔值</strong>（boolean），只有 <code>true</code>（真）或 <code>false</code>（假）两种情况。这和数字不一样！</p></blockquote><hr><h3 id="_3-在触发器中实际使用" tabindex="-1">3. 在触发器中实际使用 <a class="header-anchor" href="#_3-在触发器中实际使用" aria-label="Permalink to “3. 在触发器中实际使用”">​</a></h3><h4 id="第一步-打开触发编辑器" tabindex="-1">第一步：打开触发编辑器 <a class="header-anchor" href="#第一步-打开触发编辑器" aria-label="Permalink to “第一步：打开触发编辑器”">​</a></h4><ol><li>在World Editor中，点击顶部菜单 <strong>「触发器编辑器」</strong>（或按 F4）</li><li>双击已有触发器或新建一个触发器</li></ol><h4 id="第二步-编写数学运算动作" tabindex="-1">第二步：编写数学运算动作 <a class="header-anchor" href="#第二步-编写数学运算动作" aria-label="Permalink to “第二步：编写数学运算动作”">​</a></h4><p>在触发器的<strong>动作</strong>中添加：</p><ul><li><strong>数学运算</strong> → <strong>设置实数变量</strong> → 选择变量，设置为 <code>SquareRoot(100)</code> 的结果</li></ul><blockquote><p><strong>⚠️ 常见错误</strong>：忘记给变量初始化！在使用数学运算前，确保变量已经被声明和赋值，否则可能得到错误结果或导致游戏崩溃。</p></blockquote><hr><h3 id="小结-4" tabindex="-1">小结 <a class="header-anchor" href="#小结-4" aria-label="Permalink to “小结”">​</a></h3><p>完成本节学习后，你应该：</p><ul><li>✅ 理解原生函数与BJ辅助函数的区别</li><li>✅ 能在触发器中使用 <code>Sin</code>、<code>Cos</code>、<code>SquareRoot</code> 等数学函数</li><li>✅ 掌握整数与浮点数的转换方法</li><li>✅ 学会用 <code>and</code>、<code>or</code>、<code>not</code> 组合多个条件判断</li></ul><p>这些函数虽然简单，但组合起来就能实现技能伤害计算、距离判断等核心玩法。继续学习下一节《字符串与文本函数》，让你的地图更丰富！</p><h2 id="新手常见问题与调试技巧" tabindex="-1">新手常见问题与调试技巧 <a class="header-anchor" href="#新手常见问题与调试技巧" aria-label="Permalink to “新手常见问题与调试技巧”">​</a></h2><p>本节将帮助你识别JASS脚本中最容易犯的错误，学会查看错误信息并修复问题，了解一些基本的代码优化技巧。学完本节后，你将能够独立排查常见的脚本问题，让地图运行得更稳定流畅。</p><h3 id="新手常犯的错误汇总" tabindex="-1">新手常犯的错误汇总 <a class="header-anchor" href="#新手常犯的错误汇总" aria-label="Permalink to “新手常犯的错误汇总”">​</a></h3><ol><li><p><strong>语法错误：缺少括号或分号</strong> — JASS对语法要求严格，每个函数调用后面必须加分号<code>;</code>，每个括号必须成对出现[^3]。例如<code>call BJDebugMsg(&quot;hello&quot;</code>会报错，正确的是<code>call BJDebugMsg(&quot;hello&quot;)</code>。</p></li><li><p><strong>变量未声明就使用</strong> — 在JASS中，所有变量必须先声明（定义类型）才能使用[^4]。新手常忘记写<code>local integer i</code>就直接写<code>set i = 0</code>，这会导致&quot;未定义的变量&quot;错误。</p></li><li><p><strong>变量类型不匹配</strong> — 比如把一个整数赋值给字符串变量[^7]。<code>set myString = 100</code>会报错，因为类型不同。正确做法是<code>set myString = I2S(100)</code>将整数转为字符串。</p></li><li><p><strong>大小写错误</strong> — JASS区分大小写，<code>Function</code>和<code>function</code>是不同的。新手经常写成<code>Function main()</code>而实际上应该是<code>function main()</code>。</p></li></ol><blockquote><p><strong>⚠️ 常见错误</strong>：很多新手在复制别人的代码时会忘记修改函数名，导致&quot;函数已存在&quot;或&quot;函数未找到&quot;的错误。养成每复制一段代码就检查函数名的习惯。</p></blockquote><h3 id="jass脚本调试方法" tabindex="-1">JASS脚本调试方法 <a class="header-anchor" href="#jass脚本调试方法" aria-label="Permalink to “JASS脚本调试方法”">​</a></h3><ol><li><p><strong>使用BJDebugMsg输出信息</strong> — 这是最简单有效的调试方法[^1]。在怀疑出错的地方加入<code>call BJDebugMsg(&quot;变量x的值=&quot;+R2S(x))</code>，运行地图时屏幕上方会显示实际值，帮助你判断程序执行到了哪一步。</p></li><li><p><strong>查看触发器日志</strong> — 当地图崩溃或出错时，回到World Editor，按F12或通过&quot;场景 &gt; 触发器日志&quot;查看详细错误报告[^2]。错误信息通常会告诉你出错的函数名和行号。</p></li><li><p><strong>逐行注释法</strong> — 把可疑代码用<code>//</code>注释掉，然后逐行取消注释，观察地图何时出现问题。这种&quot;二分查找&quot;的方法特别适合定位复杂问题。</p></li><li><p><strong>检查函数参数数量</strong> — 调用函数时，参数个数和类型必须完全匹配[^8]。如果函数定义是<code>takes integer a, real b returns nothing</code>，那么调用时必须提供这两个参数，顺序也不能错。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：养成写注释的习惯！在每段重要代码前用<code>//</code>加上中文说明，比如<code>// 判断玩家是否死亡</code>。这样自己和别人都更容易理解代码逻辑，出错时也能快速定位。</p></blockquote><h3 id="脚本优化与运行效率" tabindex="-1">脚本优化与运行效率 <a class="header-anchor" href="#脚本优化与运行效率" aria-label="Permalink to “脚本优化与运行效率”">​</a></h3><ol><li><p><strong>避免在循环中频繁创建单位组</strong> — 每帧或每次触发都创建新单位组会大量消耗内存（内存泄漏）[^5]。正确做法是预先声明一个全局单位组，每次用完调用<code>call DestroyGroup(g)</code>释放，或者使用<code>ClearNativeGlueHandle</code>等函数。</p></li><li><p><strong>减少不必要的字符串操作</strong> — 字符串拼接很消耗性能[^4]。如果需要在循环中频繁拼接字符串，先在循环外定义好，用<code>SetUnitX</code>等函数代替字符串传递数据。</p></li><li><p><strong>使用局部变量代替全局变量</strong> — 全局变量在多人游戏中可能引发同步问题（Desync）[^6]。尽量在函数内部使用<code>local</code>声明的局部变量，只在必要时使用全局变量。</p></li><li><p><strong>合理使用计时器</strong> — 不要创建太多同时运行的计时器，它们会占用系统资源。将可以合并的逻辑合并到一个计时器中处理。</p></li></ol><blockquote><p><strong>💡 新手提示</strong>：优化代码时不要&quot;过度优化&quot;。先把功能做对、做出效果，等地图能正常运行后再考虑性能问题。很多时候可读性比微小的性能提升更重要。</p></blockquote><h3 id="小结-5" tabindex="-1">小结 <a class="header-anchor" href="#小结-5" aria-label="Permalink to “小结”">​</a></h3><p>完成以上学习后，你应该能够：</p><ul><li>识别并修复JASS中最常见的语法错误</li><li>使用BJDebugMsg和触发器日志定位问题代码</li><li>养成注释和检查函数参数的好习惯</li><li>了解基本的内存管理和性能优化原则</li></ul><p>建议立刻打开World Editor，尝试写一个简单的JASS脚本，故意犯几个常见错误（如漏写分号、变量类型不匹配），然后观察错误信息长什么样——这比任何教程都更直观！</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to “参考来源”">​</a></h2><p>[^1]: <a href="https://jass.fandom.com/wiki/Functions" target="_blank" rel="noreferrer">Functions - Warcraft 3 JASS Wiki</a> — accessed 2026-05-08 [^2]: <a href="https://github.com/lep/jassdoc" target="_blank" rel="noreferrer">GitHub - lep/jassdoc: Document the WarCraft 3 API</a> — accessed 2026-05-08 [^3]: <a href="https://jass.sourceforge.net/doc/" target="_blank" rel="noreferrer">JASS Manual</a> — accessed 2026-05-08 [^4]: <a href="https://blog.csdn.net/weixin_32251525/article/details/143220228" target="_blank" rel="noreferrer">《魔兽3的Jass语言参考手册》：地图编辑与脚本开发指南-CSDN博客</a> — accessed 2026-05-08 [^5]: <a href="https://www.hiveworkshop.com/threads/beginning-jass-tutorial-series.30765/" target="_blank" rel="noreferrer">Beginning JASS Tutorial Series - HIVE</a> — accessed 2026-05-08 [^6]: <a href="https://forum.wc3edit.net/viewtopic.php?t=11005" target="_blank" rel="noreferrer">[JASS Tutorials] - wc3edit.net</a> — accessed 2026-05-08 [^7]: <a href="https://wc3we.fandom.com/wiki/Jass_Coding" target="_blank" rel="noreferrer">Jass Coding | Warcraft 3 World Editor Wiki | Fandom</a> — accessed 2026-05-08 [^8]: <a href="https://www.thehelper.net/threads/is-there-a-complete-jass-function-list.54372/" target="_blank" rel="noreferrer">Is There A Complete JASS Function List? | The Helper</a> — accessed 2026-05-08</p>`,132)])])}const b=s(n,[["render",o]]);export{g as __pageData,b as default};
